INSERT INTO tool_description_overrides (operation_name, enhanced_description, is_active) VALUES ('analyze_getValidateConnectivity', E'Answers the question "Can X talk to Y?" by analyzing connectivity between specified security groups within a fabric.\nThis endpoint determines communication feasibility based on configuration policies and relationships (e.g., contracts, EPG / ESG membership).\nFor the same query, /explorer/canPrefi...', true) ON CONFLICT (operation_name) DO UPDATE SET enhanced_description = EXCLUDED.enhanced_description, updated_at = NOW();
